ALGORITHM ComputeFirstSets
INPUT: Grammar G
OUTPUT: FIRST sets for each non-terminal

BEGIN
 for each non-terminal X:
 FIRST(X) = ∅
 while sets are still changing:
 for each production X → Y₁Y₂...Yₖ:
 add all non-ε elements of FIRST(Y₁) to FIRST(X)
 if Y₁ can derive ε:
 add all non-ε elements of FIRST(Y₂) to FIRST(X)
 ...
 if all Y₁ through Yₖ can derive ε:
 add ε to FIRST(X)
END

def compute_first_sets(grammar):
 first_sets = {}
 for non_terminal in grammar:
 first_sets[non_terminal] = set()
 while True:
 changed = False
 for production in grammar:
 for symbol in production:
 if symbol in first_sets:
 first_sets[production[0]].update(first_sets[symbol] - {''})
 if '' in first_sets[symbol]:
 first_sets[production[0]].add('')
 changed = True
 if not changed:
 break
 return first_sets

ALGORITHM ComputeFollowSets
INPUT: Grammar G
OUTPUT: FOLLOW sets for each non-terminal

BEGIN
 FOLLOW(S) = {$}
 for each non-terminal X ≠ S:
 FOLLOW(X) = ∅
 while sets are still changing:
 for each production A → αBβ:
 add FIRST(β) - {ε} to FOLLOW(B)
 if β can derive ε:
 add FOLLOW(A) to FOLLOW(B)
 for each production A → αB:
 add FOLLOW(A) to FOLLOW(B)
END

def compute_follow_sets(grammar):
 follow_sets = {}
 for non_terminal in grammar:
 follow_sets[non_terminal] = set()
 follow_sets['S'].add('$')
 while True:
 changed = False
 for production in grammar:
 for i, symbol in enumerate(production):
 if symbol in follow_sets:
 if i < len(production) - 1:
 follow_sets[symbol].update(follow_sets[production[i+1]] - {''})
 if i == len(production) - 1:
 follow_sets[symbol].update(follow_sets[production[0]])
 changed = True
 if not changed:
 break
 return follow_sets
